"use client"

import React from 'react'
import SEED_QUIZZES from '../lib/seedQuizzes'

type QuizQuestion = {
  id: string
  question: string
  options: string[]
  correctIndex: number
  explanation?: string
}

export default function QuizModal({ moduleId, moduleTitle, moduleContent, onClose }: any) {
  const [loading, setLoading] = React.useState(false)
  const [questions, setQuestions] = React.useState<QuizQuestion[] | null>(null)
  const [error, setError] = React.useState<string | null>(null)
  const [source, setSource] = React.useState<string | null>(null)
  const [current, setCurrent] = React.useState(0)
  const [score, setScore] = React.useState(0)
  const [selected, setSelected] = React.useState<number | null>(null)
  const [feedback, setFeedback] = React.useState<string | null>(null)
  const [isCompleted, setIsCompleted] = React.useState(false)

  React.useEffect(() => {
    // If we have seeded questions for this module, use them immediately (5 per module)
    const seeded = (SEED_QUIZZES as any)[moduleId]
    if (Array.isArray(seeded) && seeded.length > 0) {
      const mapped: QuizQuestion[] = seeded.map((sq: any, idx: number) => ({
        id: sq.questionNumber ? `q${sq.questionNumber}` : `q${idx + 1}`,
        question: String(sq.question),
        options: sq.answerOptions.map((o: any) => o.text),
        correctIndex: sq.answerOptions.findIndex((o: any) => o.isCorrect) ?? 0,
        explanation: ''
      }))
      setQuestions(mapped)
      setSource('seed')
      setLoading(false)
      return
    }

    // Fetch generated quiz from server (AI or fallback)
    async function fetchQuiz() {
      setLoading(true)
      setError(null)
      try {
        const res = await fetch('/api/generate-quiz', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ moduleId, moduleTitle, moduleContent })
        })
        const data = await res.json().catch(() => ({}))
        setSource(data?.source || null)

        // Validate AI response shape
        const q = data?.questions
        if (!Array.isArray(q) || q.length === 0) {
          setQuestions([])
          setError('Could not generate quiz questions. Please try again.')
        } else {
          const validated: QuizQuestion[] = q
            .filter((it: any) => it && typeof it.question === 'string' && Array.isArray(it.options) && it.options.length >= 2)
            .map((it: any, idx: number) => ({
              id: it.id || `q${idx + 1}`,
              question: String(it.question),
              options: it.options.map(String),
              correctIndex: Number.isFinite(it.correctIndex) ? it.correctIndex : 0,
              explanation: it.explanation || ''
            }))

          if (validated.length === 0) {
            setQuestions([])
            setError('AI generated an unexpected format. Try again or use the sample questions.')
          } else {
            setQuestions(validated)
          }
        }
      } catch (err) {
        console.error(err)
        setQuestions([])
        setError('Failed to generate quiz. Check your network or try again.')
      } finally {
        setLoading(false)
      }
    }

    fetchQuiz()
  }, [moduleId, moduleContent, moduleTitle])

  const showDebug = React.useMemo(() => {
    if (typeof window === 'undefined') return false
    try {
      const params = new URLSearchParams(window.location.search)
      return process.env.NODE_ENV === 'development' || params.has('debug')
    } catch (e) {
      return process.env.NODE_ENV === 'development'
    }
  }, [])

  if (!questions && loading) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
        <div className="bg-white rounded-lg p-6 w-full max-w-2xl">Loading quiz…</div>
      </div>
    )
  }

  if (!questions || questions.length === 0) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
        <div className="bg-white rounded-lg p-6 w-full max-w-2xl">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-semibold">{moduleTitle} — Quiz</h2>
            <button onClick={onClose} className="text-gray-500">Close</button>
          </div>
          <p className="text-gray-600">{error || 'No quiz questions available.'}</p>
          <div className="mt-4 flex gap-3">
            <button
              onClick={() => {
                // Re-run effect by toggling moduleId (quick hack: call API again)
                setQuestions(null)
                setCurrent(0)
                setScore(0)
                setSelected(null)
                setFeedback(null)
                setError(null)
                // trigger fetch by calling the API directly
                ;(async () => {
                  setLoading(true)
                  try {
                    const res = await fetch('/api/generate-quiz', {
                      method: 'POST',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify({ moduleId, moduleTitle, moduleContent })
                    })
                    const data = await res.json().catch(() => ({}))
                    setSource(data?.source || null)
                    const q = data?.questions
                    if (!Array.isArray(q) || q.length === 0) {
                      setQuestions([])
                      setError('Could not generate quiz questions. Please try again.')
                    } else {
                      const validated: QuizQuestion[] = q
                        .filter((it: any) => it && typeof it.question === 'string' && Array.isArray(it.options) && it.options.length >= 2)
                        .map((it: any, idx: number) => ({
                          id: it.id || `q${idx + 1}`,
                          question: String(it.question),
                          options: it.options.map(String),
                          correctIndex: Number.isFinite(it.correctIndex) ? it.correctIndex : 0,
                          explanation: it.explanation || ''
                        }))

                      if (validated.length === 0) {
                        setQuestions([])
                        setError('AI returned malformed questions. Try again.')
                      } else {
                        setQuestions(validated)
                      }
                    }
                  } catch (err) {
                    console.error(err)
                    setQuestions([])
                    setError('Failed to generate quiz. Check your network or try again.')
                  } finally {
                    setLoading(false)
                  }
                })()
              }}
              className="px-4 py-2 bg-green-500 text-white rounded-full"
            >
              Retry
            </button>

            <button onClick={onClose} className="px-4 py-2 bg-gray-200 rounded">Close</button>
          </div>
        </div>
      </div>
    )
  }

  const q = questions[current]

  const handleSubmit = async () => {
    if (selected === null) return

    const isCorrect = selected === q.correctIndex
    if (isCorrect) setScore((s) => s + 1)

    // Request AI feedback for this answer
    try {
      const res = await fetch('/api/generate-quiz', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ feedbackFor: true, question: q.question, selected, correctIndex: q.correctIndex, moduleContent })
      })
      const data = await res.json().catch(() => null)
      if (!data) {
        // If server returned plain text or unexpected shape, try to read text
        const text = await res.text().catch(() => '')
        setFeedback(text || (isCorrect ? 'Correct.' : 'Incorrect.'))
      } else {
        setFeedback(typeof data.feedback === 'string' ? data.feedback : (isCorrect ? 'Correct.' : 'Incorrect.'))
      }
    } catch (err) {
      setFeedback(isCorrect ? 'Correct.' : 'Incorrect.')
    }
  }

  const finishQuiz = async () => {
    setIsCompleted(true)
    // Note: Eco points are only awarded from accepted donations.
    // Quiz completion is tracked for progress but does not add eco_points.
  }

  const next = () => {
    setFeedback(null)
    setSelected(null)
    if (current + 1 < questions.length) {
      setCurrent(current + 1)
    } else {
      finishQuiz()
    }
  }

  if (isCompleted) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
        <div className="bg-white rounded-lg p-6 w-full max-w-md text-center shadow-xl">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className="ri-trophy-line text-3xl text-green-600"></i>
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Quiz Completed!</h2>
          <p className="text-gray-600 mb-6">You scored {score} out of {questions.length}</p>
          
          <div className="bg-green-50 rounded-xl p-4 mb-6 border border-green-100">
            <p className="text-sm text-green-800 font-medium uppercase tracking-wide">Points Earned</p>
            <p className="text-3xl font-bold text-green-600">+{score * 5}</p>
          </div>

          <button 
            onClick={onClose} 
            className="w-full py-3 bg-green-600 hover:bg-green-700 text-white rounded-xl font-medium transition-colors"
          >
            Continue Learning
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
      <div className="bg-white rounded-lg p-6 w-full max-w-2xl">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-semibold">{moduleTitle} — Quiz</h2>
          {showDebug && source ? (
            <span className="ml-3 inline-block text-xs px-2 py-1 bg-gray-100 text-gray-700 rounded">{source}</span>
          ) : null}
          <button onClick={onClose} className="text-gray-500">Close</button>
        </div>

        <div>
          <div className="mb-4">
            <div className="text-sm text-gray-500">Question {current + 1} of {questions.length}</div>
            <div className="mt-2 text-lg font-medium">{q.question}</div>
          </div>

          <div className="grid gap-3">
            {q.options.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => setSelected(idx)}
                className={`text-left p-3 rounded-lg border ${selected === idx ? 'border-green-500 bg-green-50' : 'border-gray-200'} `}
              >
                {String.fromCharCode(65 + idx)}. {opt}
              </button>
            ))}
          </div>

          <div className="mt-4 flex items-center justify-between">
            <div className="text-sm text-gray-600">Score: {score}</div>
            {!feedback ? (
              <button onClick={handleSubmit} className="px-4 py-2 bg-green-500 text-white rounded-full">Submit</button>
            ) : (
              <div className="flex items-center gap-4">
                <div className="text-sm text-gray-700">{feedback}</div>
                <button onClick={next} className="px-4 py-2 bg-blue-500 text-white rounded-full">Next</button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}
